/************************************************************
 *  CODE 8 — DIAL LOGIC (v2.17 - Alineado NOMENCLATURAS_MILLAS2)
 *  ▸ Inyecta política DEFAULT si no llega system_payload
 *  ▸ Valida horario (windows) y límite por ventana (=1)
 *  ▸ Restaura pairing de DB (win_* y telefono_index)
 *  ▸ Reset del cursor SOLO al CAMBIAR DE VENTANA
 *  ▸ dayMax = 0 (sin límite diario). No hay resets nocturnos.
 *  ▸ Guard: respeta maxLifetimeTries
 *  ▸ NOTA: NO define outcomes - eso lo hace Code 2 (post-llamada)
 ************************************************************/

/* 0) Fallback de política dentro de Code8 (solo si no viene nada) */
(function ensurePolicy(){
  const hasPolicy =
    $json.system_payload &&
    ((typeof $json.system_payload === 'object' && Object.keys($json.system_payload).length) ||
     (typeof $json.system_payload === 'string' && $json.system_payload.trim().length));

  if (hasPolicy) return;

  const key = String($json.id_campania || $json.campaign_key || 'DEFAULT').toUpperCase();

  const POLICY_DEFAULT = {
    policyVersion: '2.0',
    TZ: 'America/Guayaquil',
    CC: '+593',

    // ═══════════════════════════════════════════════════════════
    // LÍMITES GENERALES (hoja Altiva)
    // ═══════════════════════════════════════════════════════════
    dayMax: 7,
    dayWait: 240,
    offHoursWait: 60,
    maxLifetimeTries: 14,

    // ═══════════════════════════════════════════════════════════
    // TOGGLES
    // ═══════════════════════════════════════════════════════════
    retryNoAnswerSameDay: false,
    hopOnVoicemail: false,
    hopOnBusy: false,
    hopWaitMin: 1,

    // ═══════════════════════════════════════════════════════════
    // PRIORIDAD
    // ═══════════════════════════════════════════════════════════
    priorityMin: -5,
    priorityMax:  0,

    // ═══════════════════════════════════════════════════════════
    // RESET DE CONTADORES
    // ═══════════════════════════════════════════════════════════
    resetContactTriesOnWindowChange: true,
    nightlyResetAt: '05:00',

    // ═══════════════════════════════════════════════════════════
    // VENTANAS HORARIAS (calcado a hoja Altiva)
    // ═══════════════════════════════════════════════════════════
    windows: [
   { id: 'WD_0800_1759', days: '1,2,3,4,5', start: '08:00', end: '17:59', max: 1, wait: 30,
      phones: 'ph_celular,ph_celular2,ph_residencial,ph_residencial2,ph_comercial,ph_telefono4' },
    { id: 'WE_0930_1230', days: '0,6',       start: '09:30', end: '12:30', max: 1, wait: 30,
      phones: 'ph_celular,ph_celular2,ph_residencial,ph_residencial2,ph_comercial,ph_telefono4' },
    ],

    // ═══════════════════════════════════════════════════════════
    // OUTCOMES: No se definen aquí - Code 2 los inyecta post-llamada
    // Code 8 es PRE-llamada, no necesita outcomes
    // ═══════════════════════════════════════════════════════════
  };

  const POLICIES = { DEFAULT: POLICY_DEFAULT };
  $json.system_payload = POLICIES[key] || POLICY_DEFAULT;
  $json._policy_source = 'Code8_fallback';
})();

function parsePayload(v){
  if (!v) return {};
  if (typeof v === 'object') return v;
  let s = String(v).trim();
  if (s.startsWith('=')) s = s.slice(1).trim();
  try { return JSON.parse(s); } catch {}
  try { return JSON.parse(JSON.parse(s)); } catch {}
  return {};
}
const parseIntSafe = (v, def = 0) => {
  const n = parseInt(v ?? def, 10);
  return Number.isNaN(n) ? def : n;
};

/* Defaults para fallback seguro */
const DEFAULT_POLICY = {
  TZ: 'America/Guayaquil',
  offHoursWait: 60,
  maxLifetimeTries: 14,
  windows: [
    { id: 'WD_0800_1759', days: '1,2,3,4,5', start: '08:00', end: '17:59', max: 1, wait: 30,
      phones: 'ph_celular,ph_celular2,ph_residencial,ph_residencial2,ph_comercial,ph_telefono4' },
    { id: 'WE_0930_1230', days: '6',       start: '09:30', end: '12:30', max: 1, wait: 30,
      phones: 'ph_celular,ph_celular2,ph_residencial,ph_residencial2,ph_comercial,ph_telefono4' },
  ],
};

/* 1) Cargar política + normalizar */
const cfgIn = parsePayload($json.system_payload) || {};
const cfg   = { ...DEFAULT_POLICY, ...cfgIn };
const TZ    = cfg.TZ || DEFAULT_POLICY.TZ;
const windows = Array.isArray(cfg.windows) && cfg.windows.length
  ? cfg.windows
  : DEFAULT_POLICY.windows;

/* Dejar la política normalizada disponible para los siguientes nodos */
$json.system_payload = cfg;

/* 2) Restaurar pairing desde DB */
function firstItemFrom(nodeName) {
  try {
    const arr = $items(nodeName, 0) || [];
    return arr.length ? (arr[0].json || {}) : null;
  } catch { return null; }
}

const DB_NODE_CANDIDATES = ["Execute a SQL query"];

let row = null;
for (const name of DB_NODE_CANDIDATES) {
  row = firstItemFrom(name);
  if (row) break;
}
if (!row) row = ($json.row || {});

if ($json.intentos_llamada == null) $json.intentos_llamada = row.intentos_llamada ?? 0;
if (!$json.last_try_ymd)            $json.last_try_ymd     = row.last_try_ymd     ?? null;
if ($json.prioridad_actual == null) $json.prioridad_actual = row.prioridad_actual ?? 0;
if (!$json.win_stamp && row.win_stamp)                 $json.win_stamp = row.win_stamp;
if ($json.win_tries == null && row.win_tries != null)  $json.win_tries = row.win_tries;
if ($json.telefono_index == null && row.telefono_index != null) {
  $json.telefono_index = row.telefono_index;
}

/* 2.5) Guard de intentos de vida */
const lifeMax = Number.isFinite(+cfg.maxLifetimeTries) ? +cfg.maxLifetimeTries : 7;
const totalTries = Number($json.intentos_llamada || 0);
if (totalTries >= lifeMax) {
  $json.puedeLlamar    = false;
  $json.reintentar_iso = null;
  $json.status_sugerido = 'agotado';
  $json.win_id    = $json.win_id ?? null;
  $json.win_stamp = $json.win_stamp ?? null;
  $json.win_tries = $json.win_tries ?? null;
  return $json;
}

/* 3) Ahora local y búsqueda de ventana activa */
const now  = new Date(new Date().toLocaleString('en-US', { timeZone: TZ }));
const hhmm = now.toTimeString().slice(0,5);
const dow  = now.getDay();

const win = windows.find(w =>
  String(w.days).split(',').map(Number).includes(dow) &&
  hhmm >= String(w.start) && hhmm <= String(w.end)
);

/* 4) Fuera de horario → no llamar, posponer offHoursWait */
const offHoursWait = parseIntSafe(cfg.offHoursWait, DEFAULT_POLICY.offHoursWait);
if (!win) {
  $json.puedeLlamar    = false;
  const t = new Date(now); t.setMinutes(t.getMinutes() + offHoursWait);
  $json.reintentar_iso = t.toISOString();
  $json.win_id         = null;
  $json.win_stamp      = $json.win_stamp ?? null;
  $json.win_tries      = $json.win_tries ?? null;
  $json.status_sugerido = 'pendiente';
  return $json;
}

/* 5) Control por ventana (hoja: max=1, wait=30) */
const ymd = now.toISOString().slice(0,10);
const winId   = win.id ?? `D${dow}-${win.start}-${win.end}`;
const stamp   = `${ymd}:${winId}`;
const maxVent = parseIntSafe(win.max, 1);
const waitWin = parseIntSafe(win.wait, offHoursWait);

/* Cambio de ventana → reset de contador y cursor */
if ($json.win_stamp !== stamp) {
  $json.win_stamp      = stamp;
  $json.win_tries      = 0;
  $json.telefono_index = 1;
}

/* Límite por ventana alcanzado → no llamar ahora */
const triesWin = parseIntSafe($json.win_tries, 0);
if (triesWin >= maxVent) {
  $json.puedeLlamar    = false;
  const t = new Date(now); t.setMinutes(t.getMinutes() + waitWin);
  $json.reintentar_iso = t.toISOString();
  $json.win_id    = winId;
  $json.win_stamp = $json.win_stamp;
  $json.win_tries = $json.win_tries;
  $json.status_sugerido = 'pendiente';
  return $json;
}

/* 6) Se puede llamar → exponer orden de teléfonos de la ventana */
$json.puedeLlamar    = true;
$json.phones         = String(win.phones || '')
  .split(',').map(s => s.trim()).filter(Boolean).join(',');
$json.phones_allowed = $json.phones;
$json.win_id         = winId;
$json.win_stamp = $json.win_stamp;
$json.win_tries = $json.win_tries;

return $json;

/*****************************************************************
 * SELECT PHONE v11 — VALIDACIÓN REAL ECUADOR
 * - Usa SOLO $json.phones (orden de la ventana).
 * - Normaliza a E.164 correctamente (EC).
 * - Valida celulares y fijos reales.
 * - Sin auto-avance ni hops.
 * - Sin recorrido circular.
 *****************************************************************/

// =====================
// CONFIG
// =====================
let cfg = {};
try {
  cfg = typeof $json.system_payload === 'string'
    ? JSON.parse($json.system_payload)
    : ($json.system_payload || {});
} catch { cfg = {}; }

const CFG = { defaultCC: (cfg.CC || cfg.defaultCC || '+593') };

// =====================
// HELPERS
// =====================
function normalizeList(v){
  if (!v) return [];
  if (Array.isArray(v)) return v;
  if (typeof v === 'object') return Object.values(v);
  return String(v).split(/[,;|]/);
}

const stripToDigitsPlus = r => (r ?? '').toString().replace(/[^\d+]/g, '');

// =====================
// VALIDACIÓN ECUADOR REAL
// =====================
const PHONE_CODES = ['02','03','04','05','06','07'];

function isValidECPhone(raw) {
  if (!raw) return false;

  let x = stripToDigitsPlus(raw);

  if (x.startsWith('+')) x = x.slice(1);

  // CELULAR
  if (/^09\d{8}$/.test(x)) return true;
  if (/^5939\d{8}$/.test(x)) return true;

  // FIJO
  if (/^2\d{6}$/.test(x)) return true;

  if (/^0\d{8}$/.test(x)) {
    const code = x.substring(0,2);
    if (PHONE_CODES.includes(code)) return true;
  }

  if (/^593\d{8,9}$/.test(x)) {
    const region = x.substring(3,5);
    if (PHONE_CODES.includes(region)) return true;
  }

  return false;
}

// =====================
// NORMALIZACIÓN E.164 (CORRECTA)
// =====================
function toE164(n){
  let x = stripToDigitsPlus(n).trim();
  if (!x) return '';

  // limpiar múltiples +
  if (x.includes('+')) {
    x = '+' + x.replace(/[+]/g, '');
  }

  // 00 → +
  if (x.startsWith('00')) x = '+' + x.slice(2);

  if (!x.startsWith('+') && CFG.defaultCC === '+593') {

    // celular local
    if (/^09\d{8}$/.test(x)) {
      x = '+593' + x.slice(1);
    }

    // fijo local
    else if (/^0\d{8}$/.test(x)) {
      x = '+593' + x.slice(1);
    }

    // ya viene como 593...
    else if (/^593\d+$/.test(x)) {
      x = '+' + x;
    }

    // fallback
    else if (/^\d{7,}$/.test(x)) {
      x = CFG.defaultCC + x;
    }
  }

  return x;
}

// =====================
// VALIDADOR FINAL
// =====================
const valid = n => {
  if (!n) return false;
  if (!/^\+\d{7,15}$/.test(n)) return false;
  return isValidECPhone(n);
};

// =====================
// CAMPOS
// =====================
const windowCols = normalizeList($json.phones).map(s => s.trim()).filter(Boolean);
const cols = [...new Set(windowCols)];

// detectar teléfonos fuera de ventana
const DIG_FIELDS = ['ph_celular','ph_celular2','ph_residencial','ph_residencial2','ph_comercial','ph_telefono4'];
const presentWithDigits = DIG_FIELDS.filter(f => /\d/.test(String($json[f] || '')));
const allowedSet = new Set(cols);

$json.hasPhonesOutsideWindow = presentWithDigits.some(f => !allowedSet.has(f));
$json.phones_outside_fields = presentWithDigits.filter(f => !allowedSet.has(f)).join(',');

// =====================
// CURSOR
// =====================
let idx = Number($json.telefono_index || 1);
if (idx < 1) idx = 1;

$json.phones_effective   = cols.join(',');
$json.telefono_index_max = cols.length;

// =====================
// SIN NÚMEROS
// =====================
if (cols.length === 0 || idx > cols.length) {
  $json.telefono_actual   = '';
  $json.telefono_field    = '';
  $json.isOutOfNumbers    = true;
  $json.hasValidPhones    = false;
  $json.telefono_try_list = [];

  $json.reason_no_number =
    cols.length === 0
      ? 'NO_ALLOWED_FIELDS_IN_WINDOW'
      : 'CURSOR_OUT_OF_RANGE';

  return $json;
}

// =====================
// SELECCIÓN
// =====================
let elegido = '';
let elegidoField = '';

const tried = [];
const seen = new Set();

for (let pos = idx - 1; pos < cols.length; pos++) {

  const field = cols[pos];
  const raw   = $json[field];
  const num   = toE164(raw);
  const ok    = valid(num);

  tried.push({ field, raw, num, valid: ok });

  if (!num) continue;
  if (seen.has(num)) continue;

  seen.add(num);

  if (ok) {
    elegido = num;
    elegidoField = field;
    break;
  }
}

// =====================
// OUTPUT
// =====================
$json.telefono_actual   = elegido;
$json.telefono_field    = elegidoField;
$json.telefono_index    = idx; // NO AVANZA
$json.isOutOfNumbers    = !elegido;
$json.hasValidPhones    = tried.some(t => t.valid);
$json.telefono_try_list = tried.slice(0, 12);

if (!elegido) {
  $json.reason_no_number = 'NO_VALID_NUMBER_IN_ALLOWED_FIELDS';
}

return $json;

/********************************************************
 * CODE 9 — Sin número elegible en la ventana (v3.5)
 * ACTUALIZADO: Alineado con NOMENCLATURAS_MILLAS2
 * - Si hay números pero la ventana no los permite → PENDIENTE
 *   y reintentar_iso = inicio de la próxima ventana que los admita.
 * - Si no hay dígitos en ningún campo → AGOTADO + DISCARDED.
 * - Si hay dígitos pero todos inválidos → AGOTADO + DISCARDED.
 ********************************************************/
const FIELDS = [
  'ph_celular','ph_celular2','ph_residencial','ph_residencial2','ph_comercial','ph_telefono4'
];

// --- helpers de política/TZ ---
function parseLoose(v){
  if (!v) return {};
  if (typeof v === 'object') return v;
  let s = String(v).trim();
  if (s.startsWith('=')) s = s.slice(1).trim();
  try { return JSON.parse(s); } catch {}
  try { return JSON.parse(JSON.parse(s)); } catch {}
  return {};
}

const DEFAULT_POLICY = {
  TZ: 'America/Guayaquil',
  offHoursWait: 60,
  windows: [
       { id: 'WD_0800_1759', days: '1,2,3,4,5', start: '08:00', end: '17:59', max: 1, wait: 30,
      phones: 'ph_celular,ph_celular2,ph_residencial,ph_residencial2,ph_comercial,ph_telefono4' },
    { id: 'WE_0930_1230', days: '0,6',       start: '09:30', end: '12:30', max: 1, wait: 30,
      phones: 'ph_celular,ph_celular2,ph_residencial,ph_residencial2,ph_comercial,ph_telefono4' },

  ],
};

let cfgIn = parseLoose($json.system_payload);
const cfg = { ...DEFAULT_POLICY, ...(cfgIn || {}) };
const TZ  = cfg.TZ || DEFAULT_POLICY.TZ;
const windows = (Array.isArray(cfg.windows) && cfg.windows.length) ? cfg.windows : DEFAULT_POLICY.windows;
const offHoursWait = Number.isFinite(+cfg.offHoursWait) ? +cfg.offHoursWait : DEFAULT_POLICY.offHoursWait;

// --- utilidades de tiempo en TZ ---
function nowTZ(){ return new Date(new Date().toLocaleString('en-US', { timeZone: TZ })); }
function minutes(hhmm){ const [h,m]=String(hhmm).split(':').map(Number); return h*60+m; }
function dateAtTZ(baseDate, hhmm){
  const [H,M] = String(hhmm).split(':').map(Number);
  const d = new Date(new Date(baseDate).toLocaleString('en-US', { timeZone: TZ }));
  d.setHours(0,0,0,0);
  d.setHours(H, M, 0, 0);
  return d;
}

// --- estado de los phones ---
const anyDigits = FIELDS.some(f => /\d/.test(String($json[f] || '')));

// Si Code7 no lo calculó, lo calculamos aquí
if (typeof $json.hasPhonesOutsideWindow === 'undefined') {
  const allowed = new Set(String($json.phones_allowed || '').split(',').map(s=>s.trim()).filter(Boolean));
  const present = FIELDS.filter(f => /\d/.test(String($json[f] || '')));
  $json.hasPhonesOutsideWindow = present.some(f => !allowed.has(f));
}
const hasOutside = Boolean($json.hasPhonesOutsideWindow);

// (1) Hay números pero en campos NO permitidos por la ventana → posponer a próxima ventana que sí los admita
if (hasOutside) {
  const presentFields = FIELDS.filter(f => /\d/.test(String($json[f] || '')));
  const now = nowTZ();
  const nowMin = minutes(now.toTimeString().slice(0,5));

  let best = null, bestWinId = null;

  for (let addDay = 0; addDay <= 7; addDay++) {
    const probe = new Date(now);
    probe.setDate(probe.getDate() + addDay);
    const dow = new Date(new Date(probe).toLocaleString('en-US', { timeZone: TZ })).getDay();

    for (const w of windows) {
      const okDay = String(w.days).split(',').map(Number).includes(dow);
      if (!okDay) continue;

      const allowed = new Set(String(w.phones||'').split(',').map(s=>s.trim()).filter(Boolean));
      const intersects = presentFields.some(f => allowed.has(f));
      if (!intersects) continue;

      const startMin = minutes(w.start);
      if (addDay === 0 && startMin <= nowMin) continue;

      const cand = dateAtTZ(probe, w.start);
      if (!best || cand < best) { best = cand; bestWinId = w.id || null; }
    }
    if (best) break;
  }

  $json.status_flujo        = 'pendiente';
  $json.telefono_actual     = '';
  $json.telefono_field      = '';
  $json.isOutOfNumbers      = true;
  $json.hasValidPhones      = true;
  $json.telefono_try_list   = [];
  $json.observaciones_internas = 'PHONES_OUTSIDE_WINDOW';
  $json.reason_no_number    = 'NUMBERS_ONLY_IN_NON_ALLOWED_FIELDS';
  $json.present_fields      = presentFields.join(',');

  const fallback = new Date(now.getTime() + offHoursWait*60000);
  const nextAt   = best || fallback;
  $json.reintentar_iso = nextAt.toISOString();
  if (bestWinId) $json.win_next_id = bestWinId;
  $json.next_window_at = best ? best.toISOString() : null;

  return $json;
}

// (2) No hay ningún dígito → cerrar como DISCARDED
// NOMENCLATURAS_MILLAS2: Nomenclatura 4, id_motivo 1005
if (!anyDigits) {
  $json.status_flujo        = 'agotado';
  $json.reintentar_iso      = null;
  $json.telefono_actual     = '';
  $json.telefono_field      = '';
  $json.isOutOfNumbers      = true;
  $json.hasValidPhones      = false;
  $json.categoria_motivo    = 'IMPOSIBLE CONTACTARSE CON EL CLIENTE';
  $json.id_nomenclatura     = 4;    // CONTACTO FALLIDO JUSTIFICADO
  $json.id_motivo           = 1005; // IMPOSIBLE CONTACTARSE CON EL CLIENTE
  $json.nomenclatura_ultima = 4;
  $json.motivo_ultimo       = 1005;
  $json.observaciones_internas = 'NO_PHONE_FIELDS';
  $json.reason_no_number    = 'NO_DIGITS_IN_ANY_FIELD';
  return $json;
}

// (3) Hay dígitos pero todos inválidos → DISCARDED
// NOMENCLATURAS_MILLAS2: Nomenclatura 4, id_motivo 1030
$json.status_flujo        = 'agotado';
$json.reintentar_iso      = null;
$json.telefono_actual     = '';
$json.telefono_field      = '';
$json.isOutOfNumbers      = true;
$json.hasValidPhones      = false;
$json.categoria_motivo    = 'IMPOSIBLE CONTACTARSE CON EL CLIENTE';
$json.id_nomenclatura     = 4;    // CONTACTO FALLIDO JUSTIFICADO
$json.id_motivo           = 1005; // IMPOSIBLE CONTACTARSE CON EL CLIENTE
$json.nomenclatura_ultima = 4;
$json.motivo_ultimo       = 1005;
$json.observaciones_internas = 'ALL_INVALID_FORMATS';
$json.reason_no_number    = 'ALL_NUMBERS_INVALID_IN_ALLOWED_FIELDS';
return $json;

for (const item of $input.all()) {
  item.json.myNewField = 1;

  // Tomamos Hour desde el nodo lejano por su nombre
  const hour = parseInt($('EJECUTA ESTO CADA 20 SEG').first().json.Hour);

  const saludoManana = Math.random() < 0.5 ? "Buenos días" : "Buen día";

  let momento;

  if (hour >= 5 && hour < 12) {
    momento = saludoManana;
  } else if (hour >= 12 && hour < 18) {
    momento = "Buenas tardes";
  } else {
    momento = "Buenas noches";
  }

  item.json.momento = momento;
}

return $input.all();

/*************************************************************
 * map_to_canonical — lee JSON {id_nomenclatura, id_motivo}
 * del agente etiquetador (Banco del Austro)
 *************************************************************/

// ---------- 1) IDs válidos por nomenclatura (para validación) ----------
// Sirve para detectar si el LLM devolvió una combinación inválida
const motivosValidos = {
  1: [null],         // ACEPTACION — no tiene sub-motivo
  2: [2, 1129, 2620, 2029, 1695, 5, 2520, 14],
  3: [20, 2683],
  4: [22, 1043, 23, 24, 25, 1005, 1130, 26, 27, 28, 29, 30],
  5: [33, 34, 35, 31, 32, 38],
  6: [39, 40],
  7: [41, 42, 44],
};

// ---------- 2) Leer JSON del LLM ----------
const rawContent = (
  $json.message?.content ||
  $json.choices?.[0]?.message?.content ||
  ""
).trim();

let etiqueta = {};
try {
  etiqueta = JSON.parse(rawContent);
} catch (e) {
  // Si el LLM no devolvió JSON válido → fallback
  etiqueta = { id_nomenclatura: 7, id_motivo: 42 };
}

// ---------- 3) Extraer y validar ----------
const idNomen  = etiqueta.id_nomenclatura ?? 7;
const idMotivo = etiqueta.id_motivo ?? null;  // null es válido para ACEPTACION

// Caso especial: ACEPTACION (id 1) no tiene sub-motivo
const esAceptacion = idNomen === 1;

const combinacionValida = esAceptacion
  ? true  // Para ACEPTACION, cualquier id_motivo null o ausente es válido
  : (motivosValidos[idNomen]?.includes(idMotivo) ?? false);

// Si no es válida, usamos fallback NO CONTESTA
const idNomenFinal  = combinacionValida ? idNomen  : 7;
const idMotivoFinal = combinacionValida ? idMotivo : 42;

// ---------- 4) Duración ----------
