if (!Array.isArray(cfg.windows)  || cfg.windows.length === 0)  cfg.windows  = DEFAULT_POLICY.windows;
if (!Array.isArray(cfg.outcomes) || cfg.outcomes.length === 0) cfg.outcomes = DEFAULT_POLICY.outcomes;

