cfg.maxLifetimeTries = num(cfg.maxLifetimeTries, DEFAULT_POLICY.maxLifetimeTries);

// 5) Normaliza ventanas (trims, únicos en phones, nums seguros)
cfg.windows = cfg.windows.map(w => {
  const list = String(w.phones || '')
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);
  const uniq = [...new Set(list)].join(',');
  return {
    id:     String(w.id    || '').trim() || null,
    days:   String(w.days  ?? '').trim(),
    start:  String(w.start ?? '').trim(),
    end:    String(w.end   ?? '').trim(),
    max:    num(w.max,  1),
    wait:   num(w.wait, cfg.offHoursWait),
    phones: uniq,
  };
});

